import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    if len(unvisited_customers) == 0:
        return None  # No more customers to visit

    distances = np.array([distance(cur_truck_pos, customer) for customer in unvisited_customers])

    truck_impact_scores = []
    for customer in unvisited_customers:
        other_truck_distances = np.array([distance(truck_pos, customer) for truck_pos in all_truck_pos if not np.array_equal(truck_pos, cur_truck_pos)])
        if len(other_truck_distances) > 0:
            truck_impact_scores.append(np.sum(1 / other_truck_distances))
        else:
            truck_impact_scores.append(0)

    # Score function combining distance and normalized truck impact
    alpha = 0.2
    combined_scores = distances + alpha * np.array(truck_impact_scores)

    best_node = np.argmin(combined_scores)

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def estimated_time_of_arrival(truck_pos, customer_pos):
        speed_estimate = 60  # Adjusted average speed: 60 units per time unit
        return np.linalg.norm(truck_pos - customer_pos) / speed_estimate

    def proximity(customer_pos):
        return -np.linalg.norm(cur_truck_pos - customer_pos)

    def competition(customer_pos):
        eta = estimated_time_of_arrival(cur_truck_pos, customer_pos)
        competing_trucks = sum(1 for pos in all_truck_pos if estimated_time_of_arrival(pos, customer_pos) < eta)
        return -competing_trucks

    def urgency(customer_pos):
        base_line_distance = np.linalg.norm(depot_pos - customer_pos)
        return -base_line_distance

    best_node = None
    best_score = float('-inf')

    for i, customer_pos in enumerate(unvisited_customers):
        score_proximity = proximity(customer_pos)
        score_competition = 1.2 * competition(customer_pos)
        score_urgency = 0.8 * urgency(customer_pos)

        total_score = score_proximity + score_competition + score_urgency

        if total_score > best_score:
            best_score = total_score
            best_node = i

    return best_node
